// ─── CALORIE BURN CALCULATION ──────────────────────────────────────────────────
function calcCalsBurned(sets, repsPerSet, weightKg, bodyWeightKg, exerciseName, rest=90) {
  const MET_MAP = {
    "жим":5.0, "тяга":5.5, "присед":6.0, "выпад":5.0, "подтяг":6.0,
    "бёрпи":8.0, "спринт":9.0, "прыжк":7.5, "наклон":3.0, "растяжк":2.5,
    "мостик":3.0, "разводк":4.0, "трицепс":4.0, "бицепс":4.5, "жим ног":5.5,
  };
  let met = 4.5;
  const nameLow = exerciseName.toLowerCase();
  for (const [key, val] of Object.entries(MET_MAP)) {
    if (nameLow.includes(key)) { met = val; break; }
  }
  // Include rest periods so time is realistic (e.g. 4 sets × 3 reps × 3s + 4 × 120s rest = ~9 min)
  const workSec = sets * repsPerSet * 3;
  const restSec = sets * (rest || 90);
  const timeMin = (workSec + restSec) / 60;
  const intensityMult = weightKg > 0 ? 1 + (weightKg / (bodyWeightKg * 2.5)) : 1;
  return Math.round((met * bodyWeightKg * 3.5 / 200) * timeMin * intensityMult);
}

