// ─── STORAGE HELPERS ──────────────────────────────────────────────────────────
const LS = {
  get: (k, def=null) => { try { const v=localStorage.getItem(k); return v?JSON.parse(v):def; } catch { return def; } },
  set: (k, v) => { try { localStorage.setItem(k, JSON.stringify(v)); } catch {} },
};

const getToday = () => new Date().toISOString().slice(0,10);
const TODAY = getToday(); // module-level for non-reactive use
const DAYS_RU = ["Вс","Пн","Вт","Ср","Чт","Пт","Сб"];
const MONTHS_RU = ["янв","фев","мар","апр","май","июн","июл","авг","сен","окт","ноя","дек"];
function fmtDate() { const d=new Date(); return `${DAYS_RU[d.getDay()]}, ${d.getDate()} ${MONTHS_RU[d.getMonth()]}`; }

// ─── APP ROOT ─────────────────────────────────────────────────────────────────
export default function App() {
  const [isDark, setIsDark] = useState(() => LS.get("fp_theme") !== "light");
  const theme = isDark ? DARK : LIGHT;
  const toggleTheme = () => { const next = !isDark; setIsDark(next); LS.set("fp_theme", next?"dark":"light"); };
  const [phase, setPhase] = useState(() => LS.get("fp_profile") ? "main" : "splash");
  const [userData, setUserData] = useState(() => LS.get("fp_profile") || {});
  const [mounted, setMounted] = useState(false);
  useEffect(() => { setTimeout(() => setMounted(true), 60); }, []);
  const handleOnboardingDone = (ud) => { LS.set("fp_profile", ud); setUserData(ud); setPhase("main"); };
  const TC = theme;
  return (
    <ThemeCtx.Provider value={{ C: theme, toggleTheme }}>
      <div style={{ minHeight:"100dvh", background:TC.outerBg, display:"flex", justifyContent:"center", alignItems:"center", fontFamily:"'Inter',sans-serif", transition:"background .4s ease", overflow:"hidden" }}>
        <style>{CSS}</style>
        <div className={`phone-wrap ${mounted?"in":""}`} style={{ width:"100%", maxWidth:430, height:"100dvh", background:TC.phoneBg, borderRadius:0, border:"none", overflow:"hidden", display:"flex", flexDirection:"column", position:"relative", transition:"background .4s ease" }}>
          <div style={{ position:"absolute", inset:0, pointerEvents:"none", zIndex:0, background:`radial-gradient(ellipse 260px 200px at 20% 0%,${TC.radial1} 0%,transparent 70%),radial-gradient(ellipse 180px 180px at 80% 100%,${TC.radial2} 0%,transparent 70%)` }}/>
          <div style={{ flex:1, overflow:"hidden", zIndex:1, display:"flex", flexDirection:"column" }}>
            {phase==="splash"     && <Splash onDone={() => setPhase("onboarding")}/>}
            {phase==="onboarding" && <Onboarding onDone={handleOnboardingDone}/>}
            {phase==="main"       && <MainApp userData={userData} onEditProfile={() => setPhase("onboarding")}/>}
          </div>
        </div>
      </div>
    </ThemeCtx.Provider>
  );
}

// ─── SPLASH ───────────────────────────────────────────────────────────────────
function Splash({ onDone }) {
  const { C } = useTheme(); const glass = makeGlass(C); const lbl = makeLbl(C); // eslint-disable-line no-unused-vars
  const [step, setStep] = useState(0);
  useEffect(() => {
    const ts = [setTimeout(()=>setStep(1),300), setTimeout(()=>setStep(2),1100), setTimeout(()=>setStep(3),2700), setTimeout(()=>onDone(),3300)];
    return () => ts.forEach(clearTimeout);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);
  return (
    <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", background:C.splashBg, opacity:step===3?0:1, transition:"opacity .6s ease" }}>
      {step>=1 && (
        <div style={{ textAlign:"center" }}>
          <div className="float" style={{ marginBottom:20, display:"flex", justifyContent:"center" }}>
            <div style={{ width:90, height:90, borderRadius:24, overflow:"hidden", display:"flex", alignItems:"center", justifyContent:"center", boxShadow:step>=2?"0 0 40px rgba(124,58,237,.35),inset 0 1px 0 rgba(255,255,255,.08)":"none", transition:"box-shadow .8s ease" }}>
              <img src="data:image/png;base64," alt="FitPulse" style={{ width:"100%", height:"100%", objectFit:"cover" }}/>
            </div>
          </div>
          <div style={{ display:"flex", justifyContent:"center", gap:1, marginBottom:10 }}>
            {"FITPULSE".split("").map((l,i) => (
              <span key={i} className="ldrop" style={{ fontFamily:"'Syne',sans-serif", fontSize:32, fontWeight:800, color:C.white, animationDelay:`${i*55}ms`, textShadow:step>=2?"0 0 30px rgba(124,58,237,.5)":"none", transition:"text-shadow .7s ease", letterSpacing:-1 }}>{l}</span>
            ))}
          </div>
          <div style={{ opacity:step>=2?1:0, transform:step>=2?"translateY(0)":"translateY(8px)", transition:"all .6s ease .5s", fontSize:11, color:C.sub, letterSpacing:3, fontWeight:500 }}>ПЕРСОНАЛЬНЫЙ ТРЕНЕР</div>
        </div>
      )}
    </div>
  );
}

// ─── ONBOARDING ───────────────────────────────────────────────────────────────
function Onboarding({ onDone }) {
  const { C } = useTheme(); const glass = makeGlass(C); const lbl = makeLbl(C); // eslint-disable-line no-unused-vars
  const [step, setStep] = useState(0);
  const [data, setData] = useState({ name:"", age:"", weight:"", height:"", gender:"", goal:"", muscles:[], level:"", days:4, activityLevel:"", diet:"" });
  const STEPS = 8;
  const next = (patch={}) => { const nd={...data,...patch}; setData(nd); if(step<STEPS-1) setStep(s=>s+1); else onDone(nd); };
  return (
    <div className="page-in" style={{ flex:1, display:"flex", flexDirection:"column", overflow:"hidden" }}>
      <StatusBar/>
      <div style={{ padding:"10px 24px 0", flexShrink:0 }}>
        <div style={{ display:"flex", gap:4, marginBottom:6 }}>
          {Array.from({length:STEPS}).map((_,i) => (
            <div key={i} style={{ flex:1, height:2, borderRadius:2, background:i<=step?C.violetSoft:C.b1, transition:"background .4s ease", boxShadow:i===step?`0 0 6px ${C.violetSoft}`:"none" }}/>
          ))}
        </div>
        <div style={{ display:"flex", justifyContent:"space-between" }}>
          <span style={{ fontSize:10, color:C.sub }}>Шаг {step+1} из {STEPS}</span>
          {step>0 && <span className="tap" onClick={()=>setStep(s=>s-1)} style={{ fontSize:10, color:C.violetSoft }}>← Назад</span>}
        </div>
      </div>
      <div style={{ flex:1, overflowY:"auto", padding:"0 24px 24px" }}>
        {step===0 && <OB0 onNext={v=>next({name:v})}/>}
        {step===1 && <OB1 data={data} onNext={v=>next(v)}/>}
        {step===2 && <OB2 onNext={v=>next({goal:v})}/>}
        {step===3 && <OB3 data={data} onNext={v=>next({muscles:v})}/>}
        {step===4 && <OB4 onNext={v=>next({level:v})}/>}
        {step===5 && <OB5 onNext={v=>next({days:v})}/>}
        {step===6 && <OB6 onNext={v=>next({activityLevel:v})}/>}
        {step===7 && <OB7 onNext={v=>next({diet:v})}/>}
      </div>
    </div>
  );
}

