// ─── HOME TAB ─────────────────────────────────────────────────────────────────
function HomeTab({ userData, workouts, nutPlan }) {
  const { C } = useTheme(); const glass = makeGlass(C); const lbl = makeLbl(C); // eslint-disable-line no-unused-vars
  const getToday = () => new Date().toISOString().slice(0,10);
  const [todayStats, setTodayStats] = useState(() => LS.get(`fp_stats_${getToday()}`) || { calBurned:0, workoutsDone:0, setsTotal:0 });
  const [todayFood,  setTodayFoodH] = useState(() => LS.get(`fp_food_${getToday()}`)  || []);
  useEffect(() => {
    const refresh = () => {
      setTodayStats(LS.get(`fp_stats_${getToday()}`) || { calBurned:0, workoutsDone:0, setsTotal:0 });
      setTodayFoodH(LS.get(`fp_food_${getToday()}`)  || []);
    };
    const id = setInterval(refresh, 2000);
    window.addEventListener('focus', refresh);
    return () => { clearInterval(id); window.removeEventListener('focus', refresh); };
  }, []);
  const eatenCal   = todayFood.reduce((s,f) => s+f.cal, 0);
  const remaining  = nutPlan.goalCal - eatenCal + todayStats.calBurned;

  const r=52, circ=2*Math.PI*r;
  const pct = Math.min((eatenCal/nutPlan.goalCal)*100, 100);
  const [offset, setOffset] = useState(circ);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => { const t=setTimeout(()=>setOffset(circ-(pct/100)*circ),400); return()=>clearTimeout(t); }, [pct]);

  const allStats = LS.get("fp_all_stats") || { totalWorkouts:0, totalCal:0, totalSets:0, streak:0, lastDate:"" };

  return (
    <div className="page-in" style={{ padding:"16px 22px 20px" }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:20 }}>
        <div>
          <p style={{ fontSize:10, color:C.sub, letterSpacing:2, marginBottom:4 }}>{fmtDate().toUpperCase()}</p>
          <h1 style={{ fontFamily:"'Syne',sans-serif", fontSize:24, color:C.white, lineHeight:1.1 }}>
            Привет, <span style={{ color:C.violetSoft }}>{userData.name||"Атлет"}</span> 👋
          </h1>
        </div>
        <div style={{ textAlign:"center" }}>
          <div style={{ width:42, height:42, borderRadius:14, background:C.violetDim, border:`1px solid rgba(124,58,237,.2)`, display:"flex", alignItems:"center", justifyContent:"center" }}>
            <Icon name="fire" size={20} color={C.violetSoft}/>
          </div>
          {allStats.streak > 0 && <p style={{ fontSize:9, color:C.amber, marginTop:2, fontWeight:700 }}>🔥{allStats.streak}</p>}
        </div>
      </div>

      {/* Calorie ring */}
      <div className="card-tap" style={{ ...glass, marginBottom:12, padding:"18px", display:"flex", alignItems:"center", gap:18, border:"1px solid rgba(124,58,237,.1)" }}>
        <div className="ring-glow">
          <svg width={120} height={120}>
            <defs><linearGradient id="calGrad" x1="0%" y1="0%" x2="100%" y2="100%"><stop offset="0%" stopColor={C.violet}/><stop offset="100%" stopColor={C.accent}/></linearGradient></defs>
            <circle cx={60} cy={60} r={r} fill="none" stroke={C.isDark?"rgba(255,255,255,0.05)":"rgba(124,58,237,.08)"} strokeWidth={9}/>
            <circle className="ring-stroke" cx={60} cy={60} r={r} fill="none" stroke="url(#calGrad)" strokeWidth={9} strokeLinecap="round" strokeDasharray={circ} strokeDashoffset={offset} transform="rotate(-90 60 60)"/>
            <text x={60} y={55} textAnchor="middle" fill={C.white} fontSize={20} fontWeight={700} fontFamily="'Syne',sans-serif">{eatenCal}</text>
            <text x={60} y={70} textAnchor="middle" fill={C.sub} fontSize={9} letterSpacing={1}>ККАЛ</text>
          </svg>
        </div>
        <div style={{ flex:1 }}>
          <span style={lbl}>СЕГОДНЯ</span>
          {[["Цель",`${nutPlan.goalCal} ккал`,C.violetSoft],["Сожжено",`${todayStats.calBurned} ккал`,C.green],["Баланс",`${Math.max(0,remaining)} ккал`,remaining<0?C.rose:C.amber]].map(([l,v,col]) => (
            <div key={l} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:7 }}>
              <span style={{ fontSize:12, color:C.muted }}>{l}</span>
              <span style={{ fontSize:12, fontWeight:600, color:col }}>{v}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Today's workout suggestion */}
      {todayStats.workoutsDone === 0 && (
        <div style={{ ...glass, marginBottom:12, padding:"13px 16px", display:"flex", alignItems:"center", gap:13, border:`1px solid ${workouts[0]?.color||C.violet}20`, background:`linear-gradient(120deg,${workouts[0]?.color||C.violet}0A,transparent)` }}>
          <div style={{ width:40, height:40, borderRadius:12, background:`${workouts[0]?.color||C.violet}15`, border:`1px solid ${workouts[0]?.color||C.violet}20`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
            <Icon name={workouts[0]?.iconName||"dumbbell"} size={18} color={workouts[0]?.color||C.violet}/>
          </div>
          <div style={{ flex:1 }}>
            <span style={{ ...lbl, marginBottom:1 }}>ТРЕНИРОВКА НА СЕГОДНЯ</span>
            <p style={{ fontSize:14, fontWeight:600, color:C.white }}>{workouts[0]?.name||"Нет тренировок"}</p>
          </div>
          <Icon name="chevron" size={16} color={C.sub}/>
        </div>
      )}
      {todayStats.workoutsDone > 0 && (
        <div style={{ ...glass, marginBottom:12, padding:"13px 16px", display:"flex", alignItems:"center", gap:13, border:`1px solid ${C.green}20`, background:`rgba(16,185,129,.03)` }}>
          <div style={{ width:40, height:40, borderRadius:12, background:`rgba(16,185,129,.12)`, border:`1px solid rgba(16,185,129,.25)`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
            <Icon name="check" size={18} color={C.green}/>
          </div>
          <div style={{ flex:1 }}>
            <span style={{ ...lbl, marginBottom:1 }}>ВЫПОЛНЕНО СЕГОДНЯ</span>
            <p style={{ fontSize:13, color:C.white }}>{todayStats.workoutsDone} тренировок · {todayStats.calBurned} ккал сожжено</p>
          </div>
        </div>
      )}

      {/* Macro bars */}
      <div className="card-tap" style={{ ...glass, marginBottom:12, padding:"16px" }}>
        <span style={lbl}>МАКРОНУТРИЕНТЫ</span>
        {(() => {
          const eaten = { p:todayFood.reduce((s,f)=>s+f.p,0), c:todayFood.reduce((s,f)=>s+f.c,0), f:todayFood.reduce((s,f)=>s+f.f,0) };
          return [["Белки",eaten.p,nutPlan.proteinG,C.violetSoft,"г"],["Углеводы",eaten.c,nutPlan.carbG,C.accent,"г"],["Жиры",eaten.f,nutPlan.fatG,C.green,"г"]].map(([label,val,max,color,unit]) => (
            <MBar key={label} label={label} val={val} max={max} color={color} unit={unit}/>
          ));
        })()}
      </div>

      {/* Mini stats */}
      <div className="stagger" style={{ display:"flex", gap:10 }}>
        {[[C.violet,"chart","Тренировок",String(allStats.totalWorkouts)],[C.green,"fire","Ккал сожжено",allStats.totalCal>999?`${(allStats.totalCal/1000).toFixed(1)}k`:String(allStats.totalCal)],[C.amber,"award","Подходов",String(allStats.totalSets)]].map(([col,ic,label,val]) => (
          <div key={label} className="card-tap" style={{ flex:1, ...glass, padding:"12px 8px", textAlign:"center", border:`1px solid ${col}14` }}>
            <div style={{ display:"flex", justifyContent:"center", marginBottom:5 }}><Icon name={ic} size={16} color={col}/></div>
            <p style={{ fontSize:15, fontWeight:700, color:col }}>{val}</p>
            <p style={{ fontSize:8, color:C.sub, marginTop:2, letterSpacing:.5 }}>{label.toUpperCase()}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

// ─── WORKOUTS TAB ─────────────────────────────────────────────────────────────
function WorkoutsTab({ workouts, userData }) {
  const { C } = useTheme(); const glass = makeGlass(C); const lbl = makeLbl(C); // eslint-disable-line no-unused-vars
  const [sel, setSel] = useState(null);
  if (sel) return <WorkoutDetail workout={sel} onBack={()=>setSel(null)} userData={userData}/>;

  const weekHistory = LS.get("fp_week_history") || [];
  const bars = Array.from({length:7}).map((_,i) => {
    const d = new Date(); d.setDate(d.getDate()-6+i);
    const dateStr = d.toISOString().slice(0,10);
    const found = weekHistory.find(h=>h.date===dateStr);
    return found ? Math.min(100, found.pct) : 0;
  });

  return (
    <div className="page-in" style={{ padding:"16px 22px" }}>
      <div style={{ marginBottom:18 }}>
        <p style={{ fontSize:10, color:C.sub, letterSpacing:2, marginBottom:4 }}>ЭТА НЕДЕЛЯ</p>
        <h1 style={{ fontFamily:"'Syne',sans-serif", fontSize:24, color:C.white }}>Тренировки</h1>
        <p style={{ fontSize:12, color:C.sub, marginTop:4 }}>Программа под твой профиль · {userData.level||"стандарт"}</p>
      </div>

      {/* Week progress bars */}
      <div className="card-tap" style={{ ...glass, marginBottom:12, padding:"14px 16px" }}>
        <span style={lbl}>АКТИВНОСТЬ 7 ДНЕЙ</span>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-end" }}>
          {["Пн","Вт","Ср","Чт","Пт","Сб","Вс"].map((d,i) => (
            <div key={d} style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:5 }}>
              <div style={{ width:28, height:52, background:C.isDark?"rgba(255,255,255,.04)":"rgba(124,58,237,.06)", borderRadius:8, overflow:"hidden", display:"flex", alignItems:"flex-end" }}>
                <div style={{ width:"100%", height:`${bars[i]}%`, borderRadius:8, background:bars[i]>0?`linear-gradient(180deg,${C.violet},${C.accent})`:"transparent", transition:"height 1s ease" }}/>
              </div>
              <span style={{ fontSize:9, color:bars[i]>0?C.violetSoft:C.sub }}>{d}</span>
            </div>
          ))}
        </div>
      </div>

      <span style={lbl}>МОЯ ПРОГРАММА</span>
      <div className="stagger" style={{ display:"flex", flexDirection:"column", gap:9 }}>
        {workouts.map(w => {
          const wHistory = LS.get("fp_week_history") || [];
          const doneToday = wHistory.some(h => h.date===TODAY && h.workoutId===w.id);
          return (
            <div key={w.id} className="card-tap" onClick={()=>setSel(w)} style={{ ...glass, padding:"13px 15px", display:"flex", alignItems:"center", gap:13, border:`1px solid ${doneToday?"rgba(16,185,129,.2)":C.b1}`, background:doneToday?"rgba(16,185,129,.03)":C.s1 }}>
              <div style={{ width:44, height:44, borderRadius:14, background:`${w.color}12`, border:`1px solid ${w.color}22`, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                <Icon name={w.iconName} size={20} color={doneToday?C.sub:w.color}/>
              </div>
              <div style={{ flex:1 }}>
                <p style={{ fontSize:14, fontWeight:600, color:doneToday?C.sub:C.white, marginBottom:2, textDecoration:doneToday?"line-through":"none" }}>{w.name}</p>
                <p style={{ fontSize:11, color:C.sub }}>{w.time} · ~{w.cal} ккал · {w.level}</p>
              </div>
              {doneToday
                ? <div style={{ width:22,height:22,borderRadius:"50%",background:"rgba(16,185,129,.12)",border:"1px solid rgba(16,185,129,.35)",display:"flex",alignItems:"center",justifyContent:"center" }}><Icon name="check" size={11} color={C.green} strokeWidth={2.4}/></div>
                : <Icon name="chevron" size={16} color={C.sub}/>
              }
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ─── WORKOUT DETAIL ───────────────────────────────────────────────────────────
